+  set: (v: number) => void;
+  on: () => () => void;
+  onChange: () => () => void;
+}
+
+function createMotionValue(initial: number): MockMotionValue {
+  const mv: MockMotionValue = {
+    __mockMotionValue: true,
+    _value: initial,
+    get: () => mv._value,
+    set: (v: number) => { mv._value = v; },
+    on: () => () => {},
+    onChange: () => () => {},
